import{_ as e,o as t,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"ADR-0003: 向量缓存记录 model/dim — 失配警告并降级，而非报错重建","description":"","frontmatter":{},"headers":[],"relativePath":"adr/0003-vectors-cache-metadata.md","filePath":"adr/0003-vectors-cache-metadata.md","lastUpdated":1784633569000}'),s={name:"adr/0003-vectors-cache-metadata.md"};function l(r,a,n,d,h,c){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="adr-0003-向量缓存记录-model-dim-—-失配警告并降级-而非报错重建" tabindex="-1">ADR-0003: 向量缓存记录 model/dim — 失配警告并降级，而非报错重建 <a class="header-anchor" href="#adr-0003-向量缓存记录-model-dim-—-失配警告并降级-而非报错重建" aria-label="Permalink to &quot;ADR-0003: 向量缓存记录 model/dim — 失配警告并降级，而非报错重建&quot;">​</a></h1><ul><li><strong>状态</strong>：Proposed（2026-07-21，随 PR 评审定稿）</li><li><strong>日期</strong>：2026-07-21</li><li><strong>关联</strong>：<a href="https://github.com/XnneHangLab/XnneHangLab/blob/dev/docs/adr/0001-llm-mode-memory.md" target="_blank" rel="noreferrer">XnneHangLab ADR-0001</a>（四次修订：向量分层与 keys.jsonl 形态）、<code>docs/reference/vectors.md</code></li></ul><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>现状：<code>vectors.keys.jsonl</code> 的 header 只记录 <code>vectors_file</code>，<strong>embedding 模型名与维度都没有记录</strong>。</p><p>风险：用户更换 embedding 端点/模型后，缓存里的旧向量与新查询向量来自不同语义空间。维度不同时会在运算处炸出难解的错误；<strong>维度相同时甚至不会报错——静默错配，融合质量悄悄劣化</strong>，且无从排查。</p><p>现有哲学（必须对齐）：embedding 失败从不 raise，静默降级 BM25-only；zero-embedding 模式是一等公民。</p><h2 id="决策" tabindex="-1">决策 <a class="header-anchor" href="#决策" aria-label="Permalink to &quot;决策&quot;">​</a></h2><h3 id="_1-header-增记模型元数据" tabindex="-1">1. header 增记模型元数据 <a class="header-anchor" href="#_1-header-增记模型元数据" aria-label="Permalink to &quot;1. header 增记模型元数据&quot;">​</a></h3><p>写缓存时在 <code>vectors.keys.jsonl</code> 首行 header 落盘：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;vectors_file&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vectors-000123.npy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;配置的模型标识&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;dim&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1024</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_2-打开时比对-失配即降级" tabindex="-1">2. 打开时比对，失配即降级 <a class="header-anchor" href="#_2-打开时比对-失配即降级" aria-label="Permalink to &quot;2. 打开时比对，失配即降级&quot;">​</a></h3><p>与当前配置的模型标识比对；端点实际返回的维度与 <code>dim</code> 不符同样按失配处理：</p><ul><li><strong>一次性警告</strong>（日志 + CLI 提示），说明缓存由哪个模型产生、当前配置是什么；</li><li>本会话内该缓存<strong>整体视为不可用</strong>，检索降级 BM25-only——零 API 成本，行为可预期；</li><li><strong>不自动重嵌</strong>：重嵌要花钱（调 embedding 端点），必须由用户显式触发（CLI 子命令或配置项，实现期定名）。content-hash 键控使重嵌天然增量、可中断续跑。</li></ul><h3 id="_3-没有-重建数据库-这个概念" tabindex="-1">3. 没有&quot;重建数据库&quot;这个概念 <a class="header-anchor" href="#_3-没有-重建数据库-这个概念" aria-label="Permalink to &quot;3. 没有&quot;重建数据库&quot;这个概念&quot;">​</a></h3><p>真相是 markdown（硬约束 3），向量只是派生缓存。换模型 = 缓存作废 + 显式增量重嵌，仅此而已。<strong>向量永不写入真相文件</strong>——不在记忆条目上&quot;预留 embedding 位置&quot;，那会毁掉&quot;磁盘无不可读真相&quot;。</p><h3 id="_4-legacy-缓存的兼容" tabindex="-1">4. legacy 缓存的兼容 <a class="header-anchor" href="#_4-legacy-缓存的兼容" aria-label="Permalink to &quot;4. legacy 缓存的兼容&quot;">​</a></h3><p>旧 header（无 <code>model</code>/<code>dim</code> 字段）：继续可用 + 警告一次（&quot;来源模型未知，建议重嵌以打标&quot;）；下次任何缓存写入自然补全 header 字段。不做升级即作废的惩罚。</p><h2 id="理由" tabindex="-1">理由 <a class="header-anchor" href="#理由" aria-label="Permalink to &quot;理由&quot;">​</a></h2><ul><li>静默错配是当前设计里唯一&quot;坏得无声无息&quot;的路径，元数据比对是最小修复。</li><li>失配后的行为完全落在既有降级路径上（BM25-only 本来就是 zero-embedding 的日常形态），不引入新状态。</li><li>&quot;警告 + 降级 + 显式重嵌&quot;比&quot;报错 + 强制重建&quot;更符合 fail-open 哲学，也不会让用户在无网/无预算时被锁死。</li></ul><h2 id="后果" tabindex="-1">后果 <a class="header-anchor" href="#后果" aria-label="Permalink to &quot;后果&quot;">​</a></h2><p><strong>正面</strong></p><ul><li>换模型从&quot;静默劣化&quot;变成&quot;显式可见、可控成本的一次操作&quot;。</li><li>header 仍是明文 jsonl，可读性不破。</li></ul><p><strong>负面 / 代价</strong></p><ul><li>模型标识以宿主配置字符串为准（同模型不同别名会被误判为失配）——文档言明即可，不做模糊匹配。</li><li>多一条 CLI 子命令（重嵌）的维护面。</li></ul><p><strong>实施</strong></p><p>改动集中在 <code>vectors.py</code>（header 读写与比对）+ CLI 一条子命令 + 测试（失配降级、legacy 兼容、维度防御）。</p>',26)])])}const g=e(s,[["render",l]]);export{u as __pageData,g as default};
